85	\begin{theorem}\leanok
86	[Cotangent exact sequence for a composition]
87	  \label{thm:cotangent_exact_sequence}
88	  \lean{AlgebraicGeometry.Scheme.cotangent_exact_sequence}
89	  \uses{def:relative_kaehler_sheaf, def:universal_derivation, def:cotangent_alpha, def:cotangent_beta, lem:cotangent_exact_structure}
90	  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$, there is an exact sequence of quasi-coherent $\struct{X}$-modules
91	  \[
92	    f^*\Omega_{Y/S} \;\xrightarrow{\;\alpha\;}\; \Omega_{X/S} \;\xrightarrow{\;\beta\;}\;
93	      \Omega_{X/Y} \;\longrightarrow\; 0,
94	  \]
95	  with $\alpha$ and $\beta$ as above. It follows by bundling the three claims of Lemma~\ref{lem:cotangent_exact_structure}.
