\begin{lemma}\leanok
[Exactness of the cotangent short complex]
  \label{lem:cotangent_exact_structure}
  \lean{AlgebraicGeometry.Scheme.cotangentExactSeq_structure}
  \uses{def:cotangent_alpha, def:cotangent_beta}
  The composition $\beta \circ \alpha$ vanishes, the resulting short complex is exact at the middle term, and $\beta$ is an epimorphism. The three ingredients are local statements whose ring-level inputs are the exactness of the Mathlib cotangent sequence $\Omega_{A'/A} \otimes_{A'} B \to \Omega_{B/A} \to \Omega_{B/A'} \to 0$, together with the surjectivity of the right-hand map.
\end{lemma}

\begin{proof}
  \uses{def:cotangent_alpha, def:cotangent_beta}
  We dispose of the three claims separately.

  \emph{Vanishing $\beta \circ \alpha = 0$.} Inject through the adjunction
  $\mathrm{pullback}\,f \dashv \mathrm{pushforward}\,f$, naturality of which converts the equation into one in $Y.\mathrm{Modules}$ of the form $(\hom_{\mathrm{Adj}}\alpha) \cdot (\mathrm{pushforward}\,f).\mathrm{map}\,\beta = 0$. The left-hand side unfolds via the universal property of $\mathrm{relativeDifferentials}'\,\phi$ to a Derivation-valued equality; testing against the canonical derivation $\delta_{\phi}$ reduces the equation pointwise to ``the derivation $\delta_{\phi_2'}$ vanishes on the image of the morphism of presheaves $\phi_2$'', which is the defining property of $\delta_{\phi_2'}$. The composed-adjunction coherence required for the unfolding is the equality $\phi_g' \cdot f^c = \mathrm{unit}\,\phi_{fg}'$ (which is \texttt{rfl} at the Scheme level via $(f \cdot g).c = g.c \cdot \mathrm{pushforward}(g).\mathrm{map}\,f.c$).

  \emph{Exactness at the middle.} Exactness of a short complex of sheaves of modules is detected stalkwise: a short complex is exact iff it is exact on every stalk. On each stalk we are reduced to the ring-level exactness $\Omega_{A'/A} \otimes_{A'} B \to \Omega_{B/A} \to \Omega_{B/A'} \to 0$ provided by Mathlib's \texttt{KaehlerDifferential.exact\_mapBaseChange\_map}. The stalkwise-exactness criterion is a small Mathlib-gap-fill (Lemma~\ref{lem:sheafOfModules_exact_iff_stalkwise} below).

  \emph{Surjectivity of $\beta$.} Epimorphism is reflected through the faithful forgetful functor $\mathrm{SheafOfModules} \to \mathrm{PresheafOfModules}$: it suffices to show $\beta.\mathrm{val}$ is an epi of presheaves. The latter follows from \texttt{PresheafOfModules.epi\_iff\_surjective} together with \texttt{KaehlerDifferential.map\_surjective} on each open. The reflection step is a small Mathlib-gap-fill (Lemma~\ref{lem:sheafOfModules_epi_of_epi_presheaf} below).
\end{proof}

\begin{lemma}\leanok
[Stalkwise detection of exactness for sheaves of modules]
  \label{lem:sheafOfModules_exact_iff_stalkwise}
  \lean{SheafOfModules.exact_iff_stalkwise}
  A short complex of sheaves of $\mathcal R$-modules is exact iff its image under each stalk functor $(-)_x$ is exact in the corresponding category of modules at $x$. This transfers an exactness statement on the sheaf side to a pointwise statement on the ring-of-stalks side, where Mathlib's $\mathrm{KaehlerDifferential}$ exactness becomes directly applicable.
\end{lemma}

\begin{lemma}\leanok
[Epimorphism reflection from presheaves to sheaves of modules]
  \label{lem:sheafOfModules_epi_of_epi_presheaf}
  \lean{SheafOfModules.epi_of_epi_presheaf}
  If $f : F \to G$ is a morphism of sheaves of $\mathcal R$-modules whose underlying morphism of presheaves $f.\mathrm{val}$ is an epi, then $f$ itself is an epi. This is immediate from the faithfulness of the forgetful functor $\mathrm{SheafOfModules}\,\mathcal R \to \mathrm{PresheafOfModules}\,\mathcal R.\mathrm{val}$ combined with the general fact that faithful functors reflect epimorphisms.
\end{lemma>

